external_knowledge:
'content_id' is a unique identifier for each piece of content; 
'num_views' represents the total number of times the content has been viewed; 
'engagement_score' is a metric that quantifies how engaging the content is, based on likes, comments, and shares.

sql:
SELECT content_id, content_type
FROM content
WHERE content_status = 'active';

SELECT content_id
FROM toxicity_scores
WHERE toxic > 0.5;

SELECT COUNT(*) AS num_actions
FROM moderation_actions
WHERE moderator_id = 1;

SELECT AVG(engagement_score) AS average_engagement
FROM content_statistics
WHERE content_id = '0';

SELECT content_id
FROM content
ORDER BY timestamp DESC;
